// =====================================================
// Alternate Fields Extension Integration
// =====================================================

const ALT_FIELD_CONFIGS = [
    { saveKey: 'alt_descriptions',      label: 'Descriptions',      textareaIds: ['editDescription', 'creatorDescription'] },
    { saveKey: 'alt_personalities',     label: 'Personalities',     textareaIds: ['editPersonality', 'creatorPersonality'] },
    { saveKey: 'alt_scenarios',         label: 'Scenarios',         textareaIds: ['editScenario', 'creatorScenario'] },
    { saveKey: 'alt_example_dialogue',  label: 'Example Dialogue',  textareaIds: ['editMesExample', 'creatorMesExample'] },
    { saveKey: 'alt_main_prompts',      label: 'Main Prompts',      textareaIds: ['editSystemPrompt', 'creatorSystemPrompt'] },
    { saveKey: 'alt_post_history',      label: 'Post-History Instructions', textareaIds: ['editPostHistoryInstructions', 'creatorPostHistory'] },
];

// Baseline snapshot + live-monitor handle for the Alt Fields popup session.
// Used by Fix 6 (change detection -> "saved" toast) and Fix 3 (textarea monitoring).
let _altFieldOpenData = null;
let _altFieldMonitorHandler = null;
let _altFieldNewIndex = -1;

/**
 * Reliable check for whether a SillyTavern extension is actually ACTIVE
 * (installed AND not disabled in the extensions menu).
 *
 * ST tracks disabled extensions in `extension_settings.disabledExtensions`,
 * which stores the full internal id (e.g. "third-party/SillyTavern-AlternateDescriptions").
 * A bare `extensionSettings?.someKey != null` check is NOT sufficient: that settings
 * entry persists even after the extension is disabled in the menu, so it would report
 * the extension as present when it is in fact off. We therefore combine:
 *   - disabled = id is in disabledExtensions
 *   - installed = disabled (implies it exists) OR a settings key is present
 *     OR the extension's DOM side-effect is visible in the parent document
 * (AlternateDescriptions has no settings key of its own, so we rely on its
 * `.alt_fields_button` injection, which only happens when it is loaded+enabled.)
 *
 * @param {string} extId - Full internal id, e.g. "third-party/SillyTavern-AlternateDescriptions"
 * @param {{settingsKey?: string, domSelector?: string}} [opts]
 * @returns {boolean}
 */
function isExtensionActive(extId, { settingsKey, domSelector } = {}) {
    const ctx = getSTContext();
    const disabled = ctx?.extensionSettings?.disabledExtensions || [];
    const isDisabled = disabled.includes(extId);
    // If it's in disabledExtensions it definitely exists; otherwise probe for a
    // settings entry or a live DOM side-effect (the extension's own injection).
    let installed = isDisabled;
    if (!installed) {
        if (settingsKey != null && ctx?.extensionSettings?.[settingsKey] != null) {
            installed = true;
        } else if (domSelector && typeof parent !== 'undefined' && parent?.document) {
            try { installed = !!parent.document.querySelector(domSelector); } catch (_) { /* cross-origin */ }
        }
    }
    return installed && !isDisabled;
}

function isAlternateFieldsInstalled() {
    return isExtensionActive('third-party/SillyTavern-AlternateDescriptions', { domSelector: '.alt_fields_button' });
}

function initAltFieldButtons() {
    const buttons = document.querySelectorAll('.alt-field-btn');
    // Only surface the Alt Fields buttons when the AlternateDescriptions extension
    // is actually installed + enabled. Otherwise users just see the plain main field.
    const active = isAlternateFieldsInstalled();
    buttons.forEach(btn => {
        btn.classList.toggle('hidden', !active);
        if (!active) return;
        btn.addEventListener('click', () => {
            const saveKey = btn.dataset.saveKey;
            if (saveKey) openAltDescriptionsPopup(saveKey);
        });
    });
}

function getAltFieldData(saveKey) {
    if (!activeChar) return [];
    return activeChar?.data?.extensions?.alternate_fields?.[saveKey] || [];
}

// Snapshot every alternate-fields array (extensions.alternate_fields.*) for diff comparison.
function collectAltFieldsSnapshot() {
    const out = {};
    for (const cfg of ALT_FIELD_CONFIGS) {
        const arr = (activeChar?.data?.extensions?.alternate_fields?.[cfg.saveKey]) || [];
        out[cfg.saveKey] = (Array.isArray(arr) ? arr : [arr]).map(s => String(s ?? ''));
    }
    return out;
}

function saveAltFieldData(saveKey, entries) {
    const ctx = getSTContext();
    if (!ctx || !activeChar) return;
    if (!activeChar.data) activeChar.data = {};
    if (!activeChar.data.extensions) activeChar.data.extensions = {};
    if (!activeChar.data.extensions.alternate_fields) activeChar.data.extensions.alternate_fields = {};
    activeChar.data.extensions.alternate_fields[saveKey] = entries;
    window.applyCardFieldUpdates?.(activeChar.avatar, { [`extensions.alternate_fields.${saveKey}`]: entries });
}

async function openAltDescriptionsPopup(saveKey) {
    const config = ALT_FIELD_CONFIGS.find(c => c.saveKey === saveKey);
    if (!config || !activeChar) return;

    await hydrateCharacter(activeChar);

    const entries = getAltFieldData(saveKey);
    const charName = activeChar?.name || 'Character';

    const targetTextareaId = config.textareaIds.find(id => document.getElementById(id));
    const targetTextarea = targetTextareaId ? document.getElementById(targetTextareaId) : null;

    // Auto-register the current field as the first alternate when none exist yet
    // (mirrors upstream AlternateDescriptions auto-save on first open). This makes
    // the live "main" field render as "In Use" instead of prompting a manual save.
    if (entries.length === 0) {
        const currentContent = (targetTextarea?.value || '').trim();
        if (currentContent) {
            const seeded = [{ title: `${config.label} #1`, content: currentContent }];
            saveAltFieldData(saveKey, seeded);
            entries = getAltFieldData(saveKey);
        }
    }

    document.getElementById('altModalTitle').textContent = `Alternate ${config.label} for ${charName}`;

    const modal = document.getElementById('altDescriptionsModal');
    const body = document.getElementById('altDescriptionsModalBody');
    const addBtn = document.getElementById('altModalAddBtn');
    const doneBtn = document.getElementById('altModalDoneBtn');
    const closeBtn = document.getElementById('closeAltDescriptionsModal');

    body.innerHTML = `
        <div class="alt-popup-intro">
            <small class="opacity50p">Save different versions of this field. Click <strong>Use</strong> to load an alternate into the editor, then save the character.</small>
        </div>
        <div id="alt-field-status"></div>
        <div id="alt-field-list"></div>`;

    const listEl = document.getElementById('alt-field-list');
    renderAltFieldList(listEl, saveKey, config, targetTextarea);

    // Fix 3: live-monitor the underlying field. When it changes we refresh the
    // status banner and the active/Use indicators without rebuilding the list
    // (mirrors upstream AlternateDescriptions setupFieldMonitoring).
    _altFieldOpenData = getAltFieldData(saveKey);
    if (targetTextarea) {
        _altFieldMonitorHandler = () => {
            renderAltFieldStatus(saveKey, config, targetTextarea);
            refreshAltFieldActiveIndicators(listEl, saveKey, targetTextarea);
        };
        targetTextarea.addEventListener('input', _altFieldMonitorHandler);
        targetTextarea.addEventListener('paste', _altFieldMonitorHandler);
    }

    addBtn.onclick = () => {
        const currentData = getAltFieldData(saveKey);
        const currentContent = targetTextarea?.value || '';
        const newIndex = currentData.length;
        currentData.push({
            title: `${config.label} #${currentData.length + 1}`,
            content: currentContent,
        });
        saveAltFieldData(saveKey, currentData);
        // Newly added alternates are NOT "In Use" by default — only the entry the
        // field was actually loaded from should keep that badge.
        _altFieldNewIndex = newIndex;
        renderAltFieldList(listEl, saveKey, config, targetTextarea);
    };

    const hideModal = () => {
        // Fix 3: detach the live-monitor listeners so they don't leak.
        if (targetTextarea && _altFieldMonitorHandler) {
            targetTextarea.removeEventListener('input', _altFieldMonitorHandler);
            targetTextarea.removeEventListener('paste', _altFieldMonitorHandler);
            _altFieldMonitorHandler = null;
        }
        // Fix 6: report alt-field edits made during this popup session.
        try {
            const open = JSON.stringify(_altFieldOpenData || []);
            const now = JSON.stringify(getAltFieldData(saveKey));
            if (open !== now) showToast('Alternate fields saved', 'success');
        } catch (_) { /* ignore */ }
        _altFieldOpenData = null;
        modal.classList.remove('visible');
    };
    doneBtn.onclick = hideModal;
    closeBtn.onclick = hideModal;
    modal.onclick = (e) => { if (e.target === modal) hideModal(); };

    modal.classList.add('visible');
}

/**
 * Renders the "current field vs saved alternates" status banner inside the
 * Alternate Fields popup. Mirrors the upstream AlternateDescriptions extension:
 * when the live field diverges from every saved alternate, prompt to "Save Current".
 * @param {string} saveKey
 * @param {object} config - entry from ALT_FIELD_CONFIGS
 * @param {HTMLTextAreaElement|null} targetTextarea
 */
function renderAltFieldStatus(saveKey, config, targetTextarea) {
    const statusEl = document.getElementById('alt-field-status');
    if (!statusEl) return;

    const currentContent = (targetTextarea?.value || '').trim();
    const entries = getAltFieldData(saveKey);
    const hasMatch = entries.some(e => (e.content || '').trim() === currentContent);

    if (!hasMatch && currentContent) {
        // Current field has been edited and no longer matches any saved alternate.
        statusEl.className = 'alt-field-status alt-field-status--modified';
        statusEl.innerHTML = `
            <i class="fa-solid fa-exclamation-triangle"></i>
            <span>Current ${config.label} has been modified and doesn't match any saved version.</span>
            <button type="button" class="cl-btn cl-btn-secondary alt-save-current-btn" style="margin-left: auto; font-size: 12px; padding: 4px 10px;">
                <i class="fa-solid fa-save"></i><span>Save Current</span>
            </button>`;
        const saveBtn = statusEl.querySelector('.alt-save-current-btn');
        if (saveBtn) {
            saveBtn.onclick = () => {
                const data = getAltFieldData(saveKey);
                const newIndex = data.length;
                data.push({ title: `${config.label} #${data.length + 1}`, content: currentContent });
                saveAltFieldData(saveKey, data);
                _altFieldNewIndex = newIndex;
                const listEl = document.getElementById('alt-field-list');
                renderAltFieldList(listEl, saveKey, config, targetTextarea);
            };
        }
    } else if (hasMatch) {
        statusEl.className = 'alt-field-status alt-field-status--ok';
        statusEl.innerHTML = `
            <i class="fa-solid fa-check-circle"></i>
            <span>Current ${config.label} matches a saved version.</span>`;
    } else {
        statusEl.className = 'alt-field-status';
        statusEl.innerHTML = '';
    }
}

/**
 * Lightweight refresh of the active-field highlight + Use-button state on every
 * alt entry, comparing each saved entry's content against the live field value.
 * Avoids a full re-render (which would drop focus while editing an entry).
 * @param {HTMLElement} listEl
 * @param {string} saveKey
 * @param {HTMLTextAreaElement|null} targetTextarea
 */
function refreshAltFieldActiveIndicators(listEl, saveKey, targetTextarea) {
    if (!listEl) return;
    const currentContent = (targetTextarea?.value || '').trim();
    const entries = getAltFieldData(saveKey);
    listEl.querySelectorAll('.alt-entry').forEach((item, i) => {
        const entryContent = ((entries[i]?.content) || '').trim();
        const isActive = entryContent === currentContent;
        item.classList.toggle('active-field', isActive);
        const useBtn = item.querySelector('.alt-use-btn');
        if (useBtn) {
            useBtn.classList.toggle('active', isActive);
            useBtn.title = isActive ? 'Already in use' : 'Load into editor';
            const span = useBtn.querySelector('span');
            const icon = useBtn.querySelector('i');
            if (span) span.textContent = isActive ? 'In Use' : 'Use';
            if (icon) icon.className = isActive ? 'fa-solid fa-check' : 'fa-solid fa-arrow-up';
        }
    });
}

function renderAltFieldList(listEl, saveKey, config, targetTextarea) {
    const entries = getAltFieldData(saveKey);
    renderAltFieldStatus(saveKey, config, targetTextarea);
    if (!entries.length) {
        listEl.innerHTML = `<div class="justifyLeft" style="padding: 12px;"><small class="opacity50p">No alternate versions saved yet. Click <strong>Add New</strong> to save the current field content as the first alternate.</small></div>`;
        return;
    }

    const currentContent = (targetTextarea?.value || '').trim();

    listEl.innerHTML = entries.map((entry, i) => {
        const entryContent = (entry.content || '').trim();
        // A freshly added entry matches the field by definition; don't flag it
        // "In Use" — only the entry the field was actually loaded from should.
        const isActive = (i === _altFieldNewIndex) ? false : (entryContent === currentContent);
        return `
        <div class="alt-entry${isActive ? ' active-field' : ''}" data-index="${i}">
            <div class="alt-entry-top-row">
                <input type="text" class="text_pole alt-entry-title" value="${entry.title?.replace(/"/g, '&quot;') || ''}" maxlength="50" placeholder="Title...">
                <span class="alt-entry-tokens" data-token-idx="${i}">...</span>
                <button type="button" class="alt-use-btn${isActive ? ' active' : ''}" data-index="${i}" title="${isActive ? 'Already in use' : 'Load into editor'}">
                    <i class="fa-solid fa-${isActive ? 'check' : 'arrow-up'}"></i>
                    <span>${isActive ? 'In Use' : 'Use'}</span>
                </button>
                <button type="button" class="alt-delete-btn" data-index="${i}" title="Delete this alternate">
                    <i class="fa-solid fa-trash"></i><span>Delete</span>
                </button>
            </div>
            <textarea class="text_pole alt-entry-content" rows="6" data-index="${i}">${entry.content || ''}</textarea>
        </div>`;
    }).join('');

    entries.forEach((entry, i) => {
        const tokenEl = listEl.querySelector(`.alt-entry-tokens[data-token-idx="${i}"]`);
        if (!tokenEl) return;
        if (!entry.content) { tokenEl.textContent = '0 tok'; return; }
        // Fix 5: robust token counting — guard the call and degrade gracefully.
        const ctx = getSTContext();
        if (ctx && typeof ctx.getTokenCountAsync === 'function') {
            Promise.resolve()
                .then(() => ctx.getTokenCountAsync(entry.content))
                .then(count => { tokenEl.textContent = (count != null && !isNaN(count)) ? `${count} tok` : '—'; })
                .catch(() => { tokenEl.textContent = '—'; });
        } else {
            tokenEl.textContent = Math.ceil((entry.content || '').length / 4) + ' tok';
        }
    });

    listEl.querySelectorAll('.alt-use-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            if (btn.classList.contains('active')) return;
            const idx = parseInt(btn.dataset.index);
            const data = getAltFieldData(saveKey);
            if (!data[idx] || !targetTextarea) return;
            // Fix 4: warn before overwriting an unsaved field edit (mirrors upstream).
            const currentContent = (targetTextarea.value || '').trim();
            const hasUnsavedChanges = currentContent && !data.some(e => (e.content || '').trim() === currentContent);
            if (hasUnsavedChanges) {
                const ok = confirm(`Your current ${config.label} has unsaved changes. Switch to this ${config.label} anyway?`);
                if (!ok) return;
            }
            targetTextarea.value = data[idx].content || '';
            targetTextarea.dispatchEvent(new Event('input', { bubbles: true }));
            renderAltFieldList(listEl, saveKey, config, targetTextarea);
            showToast?.(`Loaded "${data[idx].title || 'alternate'}" into the field`, 'success');
        });
    });

    listEl.querySelectorAll('.alt-delete-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            const idx = parseInt(btn.dataset.index);
            const data = getAltFieldData(saveKey);
            if (!confirm(`Delete "${data[idx]?.title || 'this alternate'}"?`)) return;
            data.splice(idx, 1);
            saveAltFieldData(saveKey, data);
            renderAltFieldList(listEl, saveKey, config, targetTextarea);
        });
    });

    let saveTimeout;
    function debouncedSave() {
        clearTimeout(saveTimeout);
        saveTimeout = setTimeout(() => {
            const items = listEl.querySelectorAll('.alt-entry');
            const data = getAltFieldData(saveKey);
            items.forEach((item, i) => {
                if (data[i]) {
                    data[i].title = item.querySelector('.alt-entry-title')?.value || data[i].title;
                    data[i].content = item.querySelector('.alt-entry-content')?.value || data[i].content;
                }
            });
            saveAltFieldData(saveKey, data);
        }, 500);
    }

    listEl.querySelectorAll('.alt-entry-title, .alt-entry-content').forEach(el => {
        el.addEventListener('input', debouncedSave);
    });

    // Consumed: the just-added entry has been rendered; clear so subsequent
    // renders (Use / edit / live monitor) fall back to content-match logic.
    _altFieldNewIndex = -1;
}

// =====================================================
// Card Image (avatar) replacement state — Edit tab
// =====================================================

function populateEditAvatarPreview() {
    const img = document.getElementById('modalImage');
    if (!img || !activeChar) return;
    const url = getCharacterAvatarUrl(activeChar.avatar);
    img.src = url;
    // Mobile mirrors the hero on the small header thumbnail (sidebar is hidden). 32x32 target, so ST's built-in /thumbnail is plenty and avoids re-fetching the full PNG just to shrink it.
    const headerAvatar = document.querySelector('#charModal .mobile-header-avatar');
    if (headerAvatar) headerAvatar.src = getCharacterAvatarStThumbUrl(activeChar.avatar);
}

function clearPendingAvatar() {
    if (pendingAvatarPreviewUrl) {
        try { URL.revokeObjectURL(pendingAvatarPreviewUrl); } catch (_) {}
    }
    pendingAvatarFile = null;
    pendingAvatarPreviewUrl = null;
    const badge = document.getElementById('portraitPendingBadge');
    if (badge) badge.classList.add('hidden');
    const fileInput = document.getElementById('editAvatarFileInput');
    if (fileInput) fileInput.value = '';
    populateEditAvatarPreview();
}

function refreshSaveButtonState() {
    const saveBtn = document.getElementById('saveEditBtn');
    if (!saveBtn || isEditLocked) return;
    saveBtn.disabled = false;
}

function handlePendingAvatarSelected(file) {
    if (!file || !activeChar) return;
    if (!/^image\/(png|jpe?g|webp)$/i.test(file.type)) {
        showToast('Unsupported image type. Use PNG, JPEG, or WebP.', 'error');
        return;
    }
    const MAX_BYTES = 10 * 1024 * 1024; // 10 MB
    if (file.size > MAX_BYTES) {
        showToast('Image too large (max 10 MB).', 'error');
        return;
    }
    if (pendingAvatarPreviewUrl) {
        try { URL.revokeObjectURL(pendingAvatarPreviewUrl); } catch (_) {}
    }
    pendingAvatarFile = file;
    pendingAvatarPreviewUrl = URL.createObjectURL(file);
    const img = document.getElementById('modalImage');
    if (img) img.src = pendingAvatarPreviewUrl;
    // Mirror the preview onto the mobile header thumbnail.
    const headerAvatar = document.querySelector('#charModal .mobile-header-avatar');
    if (headerAvatar) headerAvatar.src = pendingAvatarPreviewUrl;
    const badge = document.getElementById('portraitPendingBadge');
    if (badge) badge.classList.remove('hidden');
    refreshSaveButtonState();
}

function closeModal() {
    modal.classList.add('hidden');
    _modalOpenGen++;
    activeChar = null;

    // Clear avatar so stale image doesn't flash on next open
    const modalImg = document.getElementById('modalImage');
    modalImg.removeAttribute('src');
    modalImg.classList.remove('loading');

    // Reset all edit-mode DOM state (tag input, lock header, buttons, etc.)
    setEditLock(true);
    originalValues = {};
    originalRawData = {};
    _editTagsArray = [];

    // Discard any pending avatar replacement
    clearPendingAvatar();
    
    // Release window globals holding rich text content (can be large)
    window.currentCreatorNotesContent = null;
    window.currentFirstMesContent = null;
    window.currentAltGreetingsContent = null;
    
    // Clear alt greetings HTML
    const altGreetingsEl = document.getElementById('modalAltGreetings');
    if (altGreetingsEl) altGreetingsEl.innerHTML = '';
    
    // Clear creator notes iframe - disconnect ResizeObserver and release its document
    const creatorNotesEl = document.getElementById('modalCreatorNotes');
    cleanupCreatorNotesContainer(creatorNotesEl);
    
    // Clear tagline content
    const taglineEl = document.getElementById('modalProviderTagline');
    if (taglineEl) taglineEl.textContent = '';

    // Cleanup versions tab
    if (window.cleanupVersionsPane) window.cleanupVersionsPane();
    const vtContent = document.getElementById('versionsTabContent');
    if (vtContent) vtContent.innerHTML = '';
    
    if (duplicateModalState.wasOpen) {
        restoreDuplicateModalState();
        duplicateModalState.wasOpen = false; // Reset flag
    }
    else if (bulkSummaryModalState.wasOpen) {
        restoreBulkSummaryModalState();
        bulkSummaryModalState.wasOpen = false; // Reset flag
    }
}

// ==================== INFO TAB (Developer) ====================

/**
 * Populate the Info tab with character metadata and mappings
 * @param {Object} char - Character object
 */
function populateInfoTab(char) {
    const container = document.getElementById('infoTabContent');
    if (!container || !char) return;
    
    const charName = char.name || char.data?.name || 'Unknown';
    const listingName = getListingNameFromExtensions(char);
    const avatar = char.avatar || '';
    const galleryFolder = getGalleryFolderName(char);
    const chatsFolder = sanitizeFolderName(charName);
    const providerResult = window.ProviderRegistry?.getCharacterProvider(char) || null;
    const galleryId = getCharacterGalleryId(char);
    const uniqueFoldersEnabled = getSetting('uniqueGalleryFolders');
    const mediaLocStatus = char.avatar ? getMediaLocalizationStatus(char.avatar) : null;
    const isFavorite = isCharacterFavorite(char);
    
    // Get token estimate
    const tokenEstimate = estimateTokens(char);
    
    // Get embedded media URLs count
    const { embeddedUrls: sidebarEmbeddedUrls, lorebookUrls: sidebarLorebookUrls } = findCharacterMediaUrls(char, { split: true });
    
    // Get lorebook info
    const characterBook = (char.data?.character_book ?? char.character_book) ?? null;
    const lorebookEntries = characterBook?.entries?.length || 0;
    // Linked external world file (primary link) lives on the card at data.extensions.world.
    const linkedWorld = char.data?.extensions?.world || '';
    
    // Get alternate greetings count
    const altGreetings = (char.data?.alternate_greetings ?? char.alternate_greetings) ?? [];
    
    // Build HTML
    let html = '';
    
    // Section: Identity
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-user"></i> Identity</div>
        <div class="info-row">
            <span class="info-label">Card Name</span>
            <span class="info-value">${escapeHtml(charName)}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Listing Name</span>
            <span class="info-value">${listingName ? escapeHtml(listingName) : '<span style="color: var(--text-faint);">(none)</span>'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Creator</span>
            <span class="info-value">${escapeHtml(String(char.creator || char.data?.creator || '(not set)'))}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Version</span>
            <span class="info-value">${escapeHtml(String(char.character_version || char.data?.character_version || '(not set)'))}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Favorite</span>
            <span class="info-value">${isFavorite ? '<i class="fa-solid fa-star" style="color: gold;"></i> Yes' : 'No'}</span>
        </div>
    </div>`;
    
    // Section: Files & Paths
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-folder-tree"></i> Files & Paths</div>
        <div class="info-row">
            <span class="info-label">Avatar Filename</span>
            <span class="info-value info-code">${escapeHtml(avatar) || '(none)'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Gallery Folder</span>
            <span class="info-value info-code">/characters/${escapeHtml(galleryFolder)}/</span>
        </div>
        <div class="info-row">
            <span class="info-label">Chats Folder</span>
            <span class="info-value info-code">/chats/${escapeHtml(chatsFolder)}/</span>
        </div>
    </div>`;
    
    // Section: Unique Gallery ID
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-fingerprint"></i> Unique Gallery</div>
        <div class="info-row">
            <span class="info-label">Feature Enabled</span>
            <span class="info-value">${uniqueFoldersEnabled ? '<i class="fa-solid fa-check" style="color: var(--cl-success-bright);"></i> Yes' : '<i class="fa-solid fa-times" style="color: var(--text-faint);"></i> No'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Gallery ID</span>
            <span class="info-value info-code">${galleryId ? escapeHtml(galleryId) : '<span style="color: var(--text-faint);">(not assigned)</span>'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Unique Folder Name</span>
            <span class="info-value info-code">${galleryId ? escapeHtml(buildUniqueGalleryFolderName(char)) : '<span style="color: var(--text-faint);">(using standard name)</span>'}</span>
        </div>
    </div>`;
    
    // Section: Provider Link (generic - shows whichever provider owns this card)
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-link"></i> Provider Link</div>
        <div class="info-row">
            <span class="info-label">Linked</span>
            <span class="info-value">${providerResult ? '<i class="fa-solid fa-check" style="color: var(--cl-success-bright);"></i> Yes' : '<i class="fa-solid fa-times" style="color: var(--text-faint);"></i> No'}</span>
        </div>`;
    if (providerResult) {
        const { provider: linkedProvider, linkInfo } = providerResult;
        html += `<div class="info-row">
            <span class="info-label">Provider</span>
            <span class="info-value"><i class="${escapeHtml(linkedProvider.icon)}"></i> ${escapeHtml(linkedProvider.name)}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Full Path</span>
            <span class="info-value info-code">${escapeHtml(linkInfo.fullPath || '')}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Provider ID</span>
            <span class="info-value info-code">${escapeHtml(String(linkInfo.id || ''))}</span>
        </div>`;
        if (linkInfo.linkedAt) {
            html += `<div class="info-row">
                <span class="info-label">Linked At</span>
                <span class="info-value">${escapeHtml(new Date(linkInfo.linkedAt).toLocaleString())}</span>
            </div>`;
        }
    }
    html += `</div>`;

    // Section: Lorebook (embedded book + linked external world file)
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-book-atlas"></i> Lorebook</div>
        <div class="info-row">
            <span class="info-label">Embedded Book</span>
            <span class="info-value">${characterBook ? `<i class="fa-solid fa-check" style="color: var(--cl-success-bright);"></i> Yes (${lorebookEntries} ${lorebookEntries === 1 ? 'entry' : 'entries'})` : '<i class="fa-solid fa-times" style="color: var(--text-faint);"></i> No'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Linked World</span>
            <span class="info-value">${linkedWorld ? `<i class="fa-solid fa-link" style="color: var(--cl-success-bright);"></i> ${escapeHtml(linkedWorld)}` : '<span style="color: var(--text-faint);">(none)</span>'}</span>
        </div>
    </div>`;

    // Section: Media Localization
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-images"></i> Media Localization</div>
        <div class="info-row">
            <span class="info-label">Global Setting</span>
            <span class="info-value">${mediaLocStatus?.globalEnabled ? '<i class="fa-solid fa-check" style="color: var(--cl-success-bright);"></i> Enabled' : '<i class="fa-solid fa-times" style="color: var(--text-faint);"></i> Disabled'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Per-Character Override</span>
            <span class="info-value">${mediaLocStatus?.hasOverride ? (mediaLocStatus.isEnabled ? 'Force ON' : 'Force OFF') : '(none)'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Effective State</span>
            <span class="info-value">${mediaLocStatus?.isEnabled ? '<i class="fa-solid fa-check" style="color: var(--cl-success-bright);"></i> Active' : '<i class="fa-solid fa-times" style="color: var(--text-faint);"></i> Inactive'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Embedded Media URLs</span>
            <span class="info-value">${sidebarEmbeddedUrls.length} URL(s) found</span>
        </div>
        <div class="info-row">
            <span class="info-label">Lorebook Media URLs</span>
            <span class="info-value">${sidebarLorebookUrls.length} URL(s) found</span>
        </div>
    </div>`;
    
    // Section: Content Stats
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-chart-bar"></i> Content Stats</div>
        <div class="info-row">
            <span class="info-label">Est. Token Count</span>
            <span class="info-value">~${tokenEstimate.toLocaleString()} tokens</span>
        </div>
        <div class="info-row">
            <span class="info-label">Alternate Greetings</span>
            <span class="info-value">${altGreetings.length}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Lorebook Entries</span>
            <span class="info-value">${lorebookEntries}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Tags</span>
            <span class="info-value">${(getTags(char) || []).length}</span>
        </div>
    </div>`;
    
    // Section: Spec Info
    const spec = char.spec || char.data?.spec || 'unknown';
    const specVersion = char.spec_version || char.data?.spec_version || '';
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-file-code"></i> Card Spec</div>
        <div class="info-row">
            <span class="info-label">Spec</span>
            <span class="info-value info-code">${escapeHtml(spec)}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Spec Version</span>
            <span class="info-value info-code">${escapeHtml(specVersion) || '(not set)'}</span>
        </div>
    </div>`;
    
    // Section: Date Info
    const createDateRaw = getCharacterCreateDateValue(char);
    const dateCreated = createDateRaw ? new Date(createDateRaw) : null;
    const dateModified = char.date_added ? new Date(Number(char.date_added)) : null;
    const dateLastChat = char.date_last_chat ? new Date(Number(char.date_last_chat)) : null;
    
    html += `<div class="info-section">
        <div class="info-section-title"><i class="fa-solid fa-calendar"></i> Dates</div>
        <div class="info-row">
            <span class="info-label">Date Created</span>
            <span class="info-value">${formatDateTime(createDateRaw)}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Last Modified</span>
            <span class="info-value">${dateModified && !isNaN(dateModified.getTime()) ? formatDateTime(dateModified.getTime()) : '(not available)'}</span>
        </div>
        <div class="info-row">
            <span class="info-label">Last Chat</span>
            <span class="info-value">${dateLastChat && !isNaN(dateLastChat.getTime()) ? formatDateTime(dateLastChat.getTime()) : '(not available)'}</span>
        </div>
    </div>`;
    
    // Section: Raw Extensions (if any)
    const extensions = char.data?.extensions || char.extensions || {};
    // Exclude the linked provider's key since it's already shown in the Provider Link section
    const linkedProviderKey = providerResult?.provider?.id || null;
    const extensionKeys = Object.keys(extensions).filter(k => k !== linkedProviderKey);
    if (extensionKeys.length > 0) {
        html += `<div class="info-section">
            <div class="info-section-title"><i class="fa-solid fa-puzzle-piece"></i> Extensions</div>`;
        for (const key of extensionKeys) {
            const value = extensions[key];
            const displayValue = typeof value === 'object' ? JSON.stringify(value) : String(value);
            html += `<div class="info-row">
                <span class="info-label info-code">${escapeHtml(key)}</span>
                <span class="info-value info-code" style="word-break: break-all;">${escapeHtml(displayValue.substring(0, 100))}${displayValue.length > 100 ? '...' : ''}</span>
            </div>`;
        }
        html += `</div>`;
    }
    
    // Section: Actions
    html += `<div class="info-section info-actions-section">
        <div class="info-section-title"><i class="fa-solid fa-wrench"></i> Actions</div>
        <div class="info-actions">
            <button type="button" class="action-btn secondary small" id="copyRawCardDataBtn">
                <i class="fa-solid fa-copy"></i> Copy Raw Card Data
            </button>
        </div>
    </div>`;
    
    container.innerHTML = html;
    
    // Attach event handler for copy button (use activeChar for most up-to-date reference)
    const copyBtn = document.getElementById('copyRawCardDataBtn');
    if (copyBtn) {
        copyBtn.onclick = () => copyRawCardData(activeChar);
    }
}

/**
 * Copy the raw character card data to clipboard as JSON
 * @param {Object} char - Character object (optional, falls back to activeChar)
 */
function copyRawCardData(char) {
    // Use activeChar as fallback
    const character = char || activeChar;
    
    if (!character) {
        showToast('No character data available', 'error');
        return;
    }
    
    try {
        const cardData = {
            // Include spec info
            spec: character.spec || character.data?.spec || 'chara_card_v2',
            spec_version: character.spec_version || character.data?.spec_version || '2.0',
            // Include the data object (main character definition)
            data: character.data || {
                name: character.name,
                description: character.description,
                personality: character.personality,
                scenario: character.scenario,
                first_mes: character.first_mes,
                mes_example: character.mes_example,
                creator_notes: character.creator_notes,
                system_prompt: character.system_prompt,
                post_history_instructions: character.post_history_instructions,
                alternate_greetings: character.alternate_greetings || [],
                tags: character.tags || [],
                creator: character.creator,
                character_version: character.character_version,
                extensions: character.extensions || {},
                character_book: character.character_book || null,
            },
            // Include ST-specific metadata
            _meta: {
                avatar: character.avatar,
                date_added: character.date_added,
                create_date: character.create_date,
            }
        };
        
        const jsonString = JSON.stringify(cardData, null, 2);
        
        // Try modern clipboard API first, fall back to legacy method
        if (navigator.clipboard && navigator.clipboard.writeText) {
            navigator.clipboard.writeText(jsonString).then(() => {
                showToast('Card data copied to clipboard', 'success');
            }).catch(err => {
                console.error('Clipboard API failed:', err);
                // Fallback to legacy method
                copyToClipboardFallback(jsonString);
            });
        } else {
            // Use fallback for older browsers or non-secure contexts
            copyToClipboardFallback(jsonString);
        }
    } catch (error) {
        console.error('Error preparing card data:', error);
        showToast('Error preparing card data', 'error');
    }
}

/**
 * Fallback clipboard copy using textarea element
 * @param {string} text - Text to copy
 */
function copyToClipboardFallback(text) {
    try {
        const textarea = document.createElement('textarea');
        textarea.value = text;
        textarea.style.position = 'fixed';
        textarea.style.left = '-9999px';
        textarea.style.top = '-9999px';
        document.body.appendChild(textarea);
        textarea.focus();
        textarea.select();
        
        const success = document.execCommand('copy');
        document.body.removeChild(textarea);
        
        if (success) {
            showToast('Card data copied to clipboard', 'success');
        } else {
            showToast('Failed to copy to clipboard', 'error');
        }
    } catch (err) {
        console.error('Fallback copy failed:', err);
        showToast('Failed to copy to clipboard', 'error');
    }
}

