// ========================================
// WORLD INFO API
// ========================================

/**
 * Get the linked world info name for a character.
 * Checks extensions.world first, falls back to character_book.name
 * (the name ST conventionally uses when creating a world from the embedded lorebook).
 * @param {string} avatar - Character avatar filename
 * @returns {string|null} The world info name or null
 */
window.getCharacterWorldName = function(avatar) {
    const char = allCharacters.find(c => c.avatar === avatar);
    if (!char) return null;
    return char.data?.extensions?.world
        || char.data?.character_book?.name
        || null;
};

/**
 * Fetch world info data from ST's /api/worldinfo/get endpoint
 * @param {string} worldName - The world name to fetch
 * @returns {Promise<Object|null>} World info data { entries: {uid: entry, ...}, ...meta } or null
 */
window.getWorldInfoData = async function(worldName) {
    if (!worldName) return null;
    try {
        const response = await apiRequest('/worldinfo/get', 'POST', { name: worldName });
        if (response.ok) {
            return await response.json();
        }
        console.error('[getWorldInfoData] API error:', response.status);
        return null;
    } catch (error) {
        console.error('[getWorldInfoData] Error:', error);
        return null;
    }
};

/**
 * Save world info data via ST's /api/worldinfo/edit endpoint
 * @param {string} worldName - The world name to save
 * @param {Object} data - World info data object
 * @returns {Promise<boolean>} Success
 */
window.saveWorldInfoData = async function(worldName, data) {
    if (!worldName || !data) return false;
    try {
        const response = await apiRequest('/worldinfo/edit', 'POST', {
            name: worldName,
            data: data
        });
        // Any write to a world invalidates the detail-modal's rendered-box cache for it.
        if (response.ok) window.invalidateLinkedWorldRenderCache?.(worldName);
        return response.ok;
    } catch (error) {
        console.error('[saveWorldInfoData] Error:', error);
        return false;
    }
};

/**
 * List all world info files available on the server.
 * ST's only enumerator is POST /api/worldinfo/list -> [{file_id, name, extensions}].
 * file_id is the on-disk filename (no .json); name is the in-file title (falls back to file_id).
 * @returns {Promise<Array<{file_id: string, name: string, extensions: Object}>>}
 */
window.listWorldInfoFiles = async function() {
    try {
        const response = await apiRequest('/worldinfo/list', 'POST', {});
        if (response.ok) {
            const data = await response.json();
            if (Array.isArray(data)) {
                return data.map(item => {
                    if (typeof item === 'string') {
                        const id = item.replace(/\.json$/i, '');
                        return { file_id: id, name: id, extensions: {} };
                    }
                    const id = String(item.file_id ?? item.name ?? '').replace(/\.json$/i, '');
                    return { file_id: id, name: item.name || id, extensions: item.extensions || {} };
                }).filter(e => e.file_id);
            }
        }
        console.error('[listWorldInfoFiles] API error:', response.status);
    } catch (error) {
        console.error('[listWorldInfoFiles] Error:', error);
    }
    return [];
};

/**
 * Create a new (empty) world info file. ST has no dedicated create route;
 * /worldinfo/edit with an empty entries object both creates and overwrites.
 * @param {string} worldName
 * @returns {Promise<boolean>} Success
 */
window.createWorldInfo = async function(worldName) {
    if (!worldName) return false;
    return window.saveWorldInfoData(worldName, { entries: {} });
};

/**
 * Delete a world info file via ST's /api/worldinfo/delete.
 * @param {string} worldName
 * @returns {Promise<boolean>} Success
 */
window.deleteWorldInfo = async function(worldName) {
    if (!worldName) return false;
    try {
        const response = await apiRequest('/worldinfo/delete', 'POST', { name: worldName });
        if (response.ok) window.invalidateLinkedWorldRenderCache?.(worldName);
        return response.ok;
    } catch (error) {
        console.error('[deleteWorldInfo] Error:', error);
        return false;
    }
};

/**
 * Rename a world file. ST has no rename route, so this is copy-new + delete-old,
 * mirroring ST's own renameWorldInfo (save then delete). The new file gets the
 * in-file `name` updated to match so /list shows the new title too.
 * @param {string} oldName
 * @param {string} newName
 * @returns {Promise<boolean>} Success
 */
window.renameWorldInfo = async function(oldName, newName) {
    if (!oldName || !newName || oldName === newName) return false;
    // Refuse to clobber a different existing world. The /worldinfo/edit write is an
    // unconditional overwrite, so without this guard a rename onto an existing name
    // would destroy that world (the UI guards too, but this is the load-bearing check).
    const existing = await window.listWorldInfoFiles();
    if (existing.some(w => w.file_id.toLowerCase() === newName.toLowerCase())) return false;
    const data = await window.getWorldInfoData(oldName);
    if (!data) return false;
    if (data.name !== undefined) data.name = newName;
    const saved = await window.saveWorldInfoData(newName, data);
    if (!saved) return false;
    // Best-effort cleanup of the old file; the new copy already landed so a delete
    // failure leaves a harmless duplicate rather than data loss.
    await window.deleteWorldInfo(oldName);
    return true;
};

/**
 * Import a world file from a parsed JSON object (already in native { entries } shape).
 * Routes through /worldinfo/edit rather than the multipart /worldinfo/import so we
 * control the destination name directly. Caller is responsible for format conversion;
 * we only accept native ST world JSON here.
 * @param {string} worldName - destination name (no .json)
 * @param {Object} worldData - must contain an `entries` object
 * @returns {Promise<boolean>} Success
 */
window.importWorldInfoData = async function(worldName, worldData) {
    if (!worldName || !worldData || typeof worldData !== 'object') return false;
    if (!worldData.entries || typeof worldData.entries !== 'object') return false;
    return window.saveWorldInfoData(worldName, worldData);
};

/**
 * Refresh ST's internal world_names array and dropdown UI.
 * ST exposes updateWorldInfoList via SillyTavern.getContext(). This wrapper
 * calls it if available so newly created/imported worlds appear immediately
 * in the WI editor and character world picker without a page reload.
 * @returns {Promise<void>}
 */
window.updateWorldInfoList = async function() {
    try {
        const ctx = window.getSTContext?.() || SillyTavern?.getContext?.();
        if (typeof ctx?.updateWorldInfoList === 'function') {
            await ctx.updateWorldInfoList();
        }
    } catch (e) {
        console.warn('[updateWorldInfoList] Could not refresh ST world list:', e);
    }
};

/**
 * Assign a world file as the primary lorebook for a character in ST's internal
 * state. This sets characters[chid].data.extensions.world and saves the character,
 * so vanilla ST knows the embedded lorebook has already been imported and won't
 * prompt the user with "import card lore" when they view the character outside CL.
 * @param {string} avatar - Character avatar filename
 * @param {string} worldName - World/lorebook name to assign
 * @returns {Promise<boolean>} Success
 */
window.assignCharacterWorld = async function(avatar, worldName) {
    if (!avatar || !worldName) return false;
    try {
        const ctx = window.getSTContext?.() || SillyTavern?.getContext?.();
        const characters = ctx?.characters;
        if (!Array.isArray(characters)) return false;

        const chid = characters.findIndex(c => c?.avatar === avatar);
        if (chid === -1) return false;

        // Update in-memory character so vanilla ST won't prompt "import card lore"
        // for a character CL already imported. The card on disk already has the
        // world link (CL pre-links it before upload), so the next page load will
        // also see the correct state. This sync is for the current session only.
        const char = characters[chid];
        if (!char.data) char.data = {};
        if (!char.data.extensions) char.data.extensions = {};
        char.data.extensions.world = worldName;

        return true;
    } catch (e) {
        console.warn('[assignCharacterWorld] Could not assign world:', e);
        return false;
    }
};

/**
 * Merge remote V2 lorebook entries into the character's linked /worlds file.
 * Matched entries get their V2-spec fields updated; new entries are added;
 * user-only entries are preserved untouched.
 *
 * /worlds entries with no Chub match are left alone - they may be user-created
 * or creator-removed, but the safe choice for both cases is to keep them.
 * Only V2-spec fields (keys, content, enabled, etc.) are written on matched
 * entries; ST-internal fields (probability, depth, group, vectorized…) are
 * preserved so user customizations survive.
 *
 * @param {string} avatar - Character avatar filename
 * @param {Object} remoteBook - Remote V2 character_book object { entries: [...], ... }
 * @returns {Promise<boolean>} Success
 */
window.mergeRemoteLorebookIntoWorldFile = async function(avatar, remoteBook) {
    const worldName = window.getCharacterWorldName(avatar);
    if (!worldName) return false;
    const worldData = await window.getWorldInfoData(worldName);
    if (!worldData?.entries) return false;

    const remoteEntries = remoteBook?.entries || [];
    if (remoteEntries.length === 0) return true;

    // Build a quick lookup of world entries by expanded keys for matching
    const worldList = Object.values(worldData.entries).filter(e => e && typeof e === 'object');

    const expandKeys = (keys) => {
        const set = new Set();
        for (const k of (keys || [])) {
            for (const part of String(k).split(',')) {
                const t = part.toLowerCase().trim();
                if (t) set.add(t);
            }
        }
        return set;
    };

    const jaccard = (a, b) => {
        if (a.size === 0 || b.size === 0) return 0;
        let inter = 0;
        for (const k of a) { if (b.has(k)) inter++; }
        const union = new Set([...a, ...b]).size;
        return union > 0 ? inter / union : 0;
    };

    const nameMatch = (wa, rb) => {
        const a = (wa.comment || '').toLowerCase().trim();
        const b = (rb.name || rb.comment || '').toLowerCase().trim();
        if (!a || !b) return 0;
        if (a === b) return 1;
        if (a.includes(b) || b.includes(a)) return 0.8;
        return 0;
    };

    // Match each remote entry against world entries
    const matchedWorldUids = new Set();
    const unmatched = [];

    for (const remote of remoteEntries) {
        const rKeys = expandKeys(remote.keys);
        let bestUid = null;
        let bestScore = 0;

        for (const we of worldList) {
            if (matchedWorldUids.has(we.uid)) continue;
            const wKeys = expandKeys(we.key);
            let score = jaccard(rKeys, wKeys);
            if (score === 0) score = nameMatch(we, remote);
            if (score > bestScore) {
                bestScore = score;
                bestUid = we.uid;
            }
        }

        if (bestUid != null && bestScore > 0.3) {
            matchedWorldUids.add(bestUid);
            // Update the matched world entry's V2-spec fields
            const target = worldData.entries[bestUid];
            if (remote.keys !== undefined) target.key = remote.keys;
            if (remote.secondary_keys !== undefined) target.keysecondary = remote.secondary_keys;
            if (remote.content !== undefined) target.content = remote.content;
            if (remote.enabled !== undefined) target.disable = !remote.enabled;
            if (remote.selective !== undefined) target.selective = remote.selective;
            if (remote.constant !== undefined) target.constant = remote.constant;
            if (remote.insertion_order !== undefined) target.order = remote.insertion_order;
            if (remote.name !== undefined) target.comment = remote.name;
            if (remote.case_sensitive !== undefined) target.caseSensitive = remote.case_sensitive;
        } else {
            unmatched.push(remote);
        }
    }

    // Add unmatched remote entries as new world entries
    const existingUids = Object.keys(worldData.entries).map(Number).filter(n => !isNaN(n));
    let nextUid = existingUids.length > 0 ? Math.max(...existingUids) + 1 : 0;

    for (const entry of unmatched) {
        const uid = nextUid++;
        worldData.entries[uid] = {
            uid,
            key: entry.keys || [],
            keysecondary: entry.secondary_keys || [],
            comment: entry.name || entry.comment || '',
            content: entry.content || '',
            constant: entry.constant ?? false,
            selective: entry.selective ?? true,
            selectiveLogic: 0,
            addMemo: !!(entry.name || entry.comment),
            order: entry.insertion_order ?? 100,
            position: entry.position === 'before_char' ? 0 : entry.position === 'after_char' ? 1 : Number(entry.position) || 0,
            disable: !(entry.enabled ?? true),
            excludeRecursion: false,
            preventRecursion: false,
            delayUntilRecursion: false,
            probability: 100,
            useProbability: true,
            depth: 4,
            group: '',
            groupOverride: false,
            groupWeight: 100,
            scanDepth: null,
            caseSensitive: entry.case_sensitive ?? null,
            matchWholeWords: null,
            useGroupScoring: null,
            automationId: '',
            role: 0,
            vectorized: false,
            sticky: null,
            cooldown: null,
            delay: null,
            displayIndex: uid,
            extensions: {
                position: entry.position === 'before_char' ? 0 : entry.position === 'after_char' ? 1 : Number(entry.position) || 0,
                exclude_recursion: false,
                display_index: uid,
                probability: 100,
                useProbability: true,
                depth: 4,
                selectiveLogic: 0,
                group: '',
                group_override: false,
                group_weight: 100,
                prevent_recursion: false,
                delay_until_recursion: false,
                scan_depth: null,
                case_sensitive: entry.case_sensitive ?? null,
                match_whole_words: null,
                use_group_scoring: null,
                automation_id: '',
                role: 0,
                vectorized: false,
            },
        };
    }

    return await window.saveWorldInfoData(worldName, worldData);
};

/**
 * Primitive card-write operation. Takes a char object directly (caller already has the ref).
 * Hydrates the char, preflight-cleans null pollution, builds the merge-attributes payload,
 * sends it, and syncs in-memory state on both the passed char and the matching allCharacters entry.
 *
 * Does NOT do convenience side effects (gallery folder rename, ST main-window notify). Callers
 * that want those should use applyCardFieldUpdates instead.
 *
 * @param {Object} char - the character object (live ref, mutated in place).
 * @param {Object<string, *>} fieldUpdates - dot-path keys to values. Pass ST_UNSET_SENTINEL as value to delete an extension key (e.g. {'extensions.chub': ST_UNSET_SENTINEL}).
 * @returns {Promise<{ok: boolean, response?: Response}>}
 */
async function writeCardFields(char, fieldUpdates, opts = {}) {
    if (!char) {
        console.error('[writeCardFields] No char provided');
        return { ok: false };
    }

    try {
        // Must hydrate before building the merge payload - slim chars lack heavy fields
        // and sending undefined would erase existing content on the server.
        await hydrateCharacter(char);

        // PRE-FLIGHT: sentinel-delete null-valued extension keys before the main write; ST otherwise drops object writes aimed at a null namespace. No-op on older ST.
        const existingExtRaw = char.data?.extensions || char.extensions || {};
        const polluted = Object.keys(existingExtRaw).filter(k => existingExtRaw[k] === null);
        if (polluted.length > 0) {
            const deleteValue = await getExtensionDeleteValue();
            if (deleteValue !== null) {
                try {
                    const cleanupExt = {};
                    for (const k of polluted) cleanupExt[k] = deleteValue;
                    await apiRequest('/characters/merge-attributes', 'POST', {
                        avatar: char.avatar,
                        create_date: char.create_date,
                        data: { extensions: cleanupExt, create_date: char.create_date },
                    });
                    // Mirror server-side cleanup in memory so the main payload spread doesnt carry the null forward.
                    for (const k of polluted) delete char.data.extensions[k];
                } catch (cleanupErr) {
                    console.warn('[writeCardFields] Null-pollution cleanup failed; main payload may still trip ST deepMerge:', cleanupErr);
                }
            }
        }

        // Build update payload preserving all existing data
        const existingExtensions = char.data?.extensions || char.extensions || {};
        const existingCreateDate = char.create_date;
        const existingSpec = char.spec || char.data?.spec;
        const existingSpecVersion = char.spec_version || char.data?.spec_version;
        const existingData = char.data || {};

        // Treat null/undefined alike when descending so legacy null-polluted namespaces dont throw on the leaf write.
        const setNestedValue = (obj, path, value) => {
            const keys = path.split('.');
            const lastKey = keys.pop();
            const target = keys.reduce((o, k) => {
                if (o[k] == null) o[k] = {};
                return o[k];
            }, obj);
            target[lastKey] = value;
        };

        // Resolve SENTINEL values centrally so callers can pass ST_UNSET_SENTINEL freely; degrades to null on old ST.
        const deleteValue = await getExtensionDeleteValue();
        const resolvedUpdates = {};
        for (const [field, value] of Object.entries(fieldUpdates)) {
            resolvedUpdates[field] = value === ST_UNSET_SENTINEL ? deleteValue : value;
        }

        // Start with existing data
        const updatedData = { ...existingData };
        // Deep-clone the extensions subtree so a nested write (eg. extensions.chub.tagline) mutates this
        // copy, not the live char.data.extensions, until the round trip succeeds.
        updatedData.extensions = (existingExtensions && typeof existingExtensions === 'object')
            ? JSON.parse(JSON.stringify(existingExtensions))
            : {};

        for (const [field, value] of Object.entries(resolvedUpdates)) {
            const mapped = field.startsWith('depth_prompt.') ? 'extensions.' + field : field;
            setNestedValue(updatedData, mapped, value);
        }

        const payload = {
            avatar: char.avatar,
            ...(existingSpec && { spec: existingSpec }),
            ...(existingSpecVersion && { spec_version: existingSpecVersion }),
            name: updatedData.name,
            description: updatedData.description,
            first_mes: updatedData.first_mes,
            personality: updatedData.personality,
            scenario: updatedData.scenario,
            mes_example: updatedData.mes_example,
            system_prompt: updatedData.system_prompt,
            post_history_instructions: updatedData.post_history_instructions,
            creator_notes: updatedData.creator_notes,
            creator: updatedData.creator,
            character_version: updatedData.character_version,
            tags: updatedData.tags,
            alternate_greetings: updatedData.alternate_greetings,
            character_book: updatedData.character_book,
            create_date: existingCreateDate,
            data: updatedData,
            // Root-only fields (chat, fav, create_date) live outside data; ST's
            // import strips them and dot-path updates cant reach them.
            ...(opts.rootFields || {}),
        };

        const response = await apiRequest('/characters/merge-attributes', 'POST', payload);
        if (!response.ok) {
            console.error('[writeCardFields] API error:', response.status);
            return { ok: false, response };
        }

        // Strip resolved sentinels from the in-memory copy so readers never see the literal wire value.
        const cleanSentinels = (obj) => {
            if (!obj || typeof obj !== 'object') return;
            for (const k of Object.keys(obj)) {
                if (obj[k] === ST_UNSET_SENTINEL) delete obj[k];
                else if (obj[k] && typeof obj[k] === 'object') cleanSentinels(obj[k]);
            }
        };
        cleanSentinels(updatedData);

        // In-memory sync. Mutate the passed char and the matching allCharacters entry (which may be the same reference or different).
        char.data = updatedData;
        for (const [field, value] of Object.entries(fieldUpdates)) {
            if (!field.includes('.') && value !== ST_UNSET_SENTINEL) char[field] = value;
        }
        for (const [field, value] of Object.entries(opts.rootFields || {})) char[field] = value;
        const charIndex = allCharacters.findIndex(c => c.avatar === char.avatar);
        if (charIndex !== -1 && allCharacters[charIndex] !== char) {
            allCharacters[charIndex].data = updatedData;
            for (const [field, value] of Object.entries(fieldUpdates)) {
                if (!field.includes('.') && value !== ST_UNSET_SENTINEL) allCharacters[charIndex][field] = value;
            }
            for (const [field, value] of Object.entries(opts.rootFields || {})) allCharacters[charIndex][field] = value;
        }
        if (updatedData.extensions) _extensionsCache.set(char.avatar, updatedData.extensions);
        // Under ST lazy loading the post-save refetch restores the cached estimate, so refresh it at the write.
        if (TOKEN_ESTIMATE_FIELDS.some(f => f in fieldUpdates)) {
            const tok = computeTokenEstimate(char);
            char._tokenEstimate = tok;
            if (charIndex !== -1) allCharacters[charIndex]._tokenEstimate = tok;
            _tokenEstimateCache.set(char.avatar, tok);
        }

        // The Online In-Library lookup base is keyed on name+creator; a surgical write that
        // changes either must invalidate it (other edit paths refresh via fetchCharacters).
        const touchedNameOrCreator = Object.keys(fieldUpdates).some(
            f => f === 'name' || f === 'creator' || f.endsWith('.name') || f.endsWith('.creator')
        );
        if (touchedNameOrCreator) window.ProviderRegistry?.invalidateBrowseLookupBase?.();

        return { ok: true, response };
    } catch (error) {
        console.error('[writeCardFields] Error:', error);
        return { ok: false };
    }
}

/**
 * Convenience wrapper for callers that have an avatar but not a char ref.
 * Looks up the char, calls writeCardFields, then runs convenience side effects:
 *   - Gallery folder rename if data.name changed.
 *   - notifySTCharacterEdited to refresh ST main window.
 *
 * Orchestrators with their own gallery-rename or ST-notify logic should call writeCardFields
 * directly to avoid duplicate side effects.
 *
 * @param {string} avatar - Character avatar filename
 * @param {Object} fieldUpdates - Object with field paths as keys (supports dot notation)
 * @param {Object} [opts] - awaitNotify: await the ST resync before returning, so a follow-on implicit card save cannot clobber this write. rootFields: payload-root key/values for fields ST keeps outside data (chat, fav, create_date).
 * @returns {Promise<boolean>} Success status
 */
window.applyCardFieldUpdates = async function(avatar, fieldUpdates, opts = {}) {
    const char = allCharacters.find(c => c.avatar === avatar);
    if (!char) {
        console.error('[applyCardFieldUpdates] Character not found:', avatar);
        return false;
    }

    // Capture name BEFORE write for gallery-rename comparison. writeCardFields will mutate char.data in place.
    const oldName = char.data?.name || char.name || '';

    const result = await writeCardFields(char, fieldUpdates, { rootFields: opts.rootFields });
    if (!result.ok) return false;

    // Convenience side effects. Failure here doesn't roll back the write.
    try {
        const newName = char.data?.name || char.name || '';
        if (oldName && newName && oldName !== newName) {
            const galleryId = getCharacterGalleryId(char);
            if (galleryId && getSetting('uniqueGalleryFolders')) {
                await handleGalleryFolderRename(char, oldName, newName, galleryId);
            }
        }
        // awaitNotify resyncs ST in-memory before ST's openCharacterChat implicit-save can clobber this out-of-band write
        if (opts.awaitNotify) {
            await notifySTCharacterEdited(avatar);
        } else {
            notifySTCharacterEdited(avatar);
        }
    } catch (sideErr) {
        console.warn('[applyCardFieldUpdates] Side effect failed (write succeeded):', sideErr);
    }

    debugLog('[applyCardFieldUpdates] Updated', Object.keys(fieldUpdates).length, 'fields for:', avatar);
    return true;
};
window.writeCardFields = writeCardFields;

// Expose allCharacters as a getter so CoreAPI always gets current value
Object.defineProperty(window, 'allCharacters', {
    get: () => allCharacters,
    configurable: true
});

// Expose currentCharacters as a getter for filtered/displayed characters
Object.defineProperty(window, 'currentCharacters', {
    get: () => currentCharacters,
    configurable: true
});

// Expose activeChar with getter/setter for CoreAPI (used by openProviderLinkModal)
Object.defineProperty(window, 'activeChar', {
    get: () => activeChar,
    set: (char) => { activeChar = char; },
    configurable: true
});
